// ========================================
// GL365 Jobber Event Normalizer
// ========================================
// Maps Jobber webhook payloads to GL365 journal format.
//
// Jobber events:
//   job_created     → booking_created
//   job_completed   → job_completed
//   job_cancelled   → booking_cancelled
//   client_created  → new_customer
//   invoice_created → invoice_created
//   payment_received → payment_received
//   visit_completed → visit_completed
//   quote_created   → estimate_sent
//   quote_approved  → estimate_approved

const input = $input.first().json;
const event = input.event || input.topic || '';
const data = input.data || input.webHookEvent?.data || input;

const eventMap = {
  'job_created': 'booking_created',
  'job_updated': 'job_updated',
  'job_completed': 'job_completed',
  'job_cancelled': 'booking_cancelled',
  'client_created': 'new_customer',
  'invoice_created': 'invoice_created',
  'payment_received': 'payment_received',
  'visit_completed': 'visit_completed',
  'quote_created': 'estimate_sent',
  'quote_approved': 'estimate_approved'
};

let importance = 'normal';
if (event === 'job_cancelled') importance = 'high';
if (event === 'quote_approved') importance = 'high';

let sentiment = 'neutral';
if (['job_completed', 'payment_received', 'quote_approved'].includes(event)) sentiment = 'positive';
if (event === 'job_cancelled') sentiment = 'negative';

const client = data.client || data.customer || {};
const job = data.job || data;
const property = data.property || job.property || {};

const normalized = {
  tenant_id: input.metadata?.tenant_id || '',
  contact_phone: client.phone || client.phones?.[0]?.number || '',
  contact_email: client.email || client.emails?.[0]?.address || '',
  contact_name: client.name || [client.first_name, client.last_name].filter(Boolean).join(' ') || '',
  source: 'jobber',
  event_type: eventMap[event] || event || 'unknown',
  raw_summary: `Jobber ${event}: ${job.title || job.description || ''} for ${client.name || 'client'} at ${property.address?.street || ''}`.trim(),
  raw_data: input,
  sentiment,
  importance,
  job_title: job.title || job.description || '',
  job_total: job.total || '',
  job_address: property.address ? [property.address.street, property.address.city].filter(Boolean).join(', ') : '',
  assigned_to: job.assigned_to?.name || ''
};

return [{ json: normalized }];

const input = $input.first().json;
const prevData = $('Normalize Jobber Event').first().json;
let summary = '';
try { summary = input.choices?.[0]?.message?.content || prevData.raw_summary; } catch { summary = prevData.raw_summary; }
return [{ json: { ...prevData, summary: summary.trim().replace(/^["']|["']$/g, '') } }];
